mapper.select:
/* TM_ECS_INTN_SCRIN_Dao_retrieveScrin */ SELECT '0' AS CHK, A.scrin_id, --화면ID A.intn_sys_div_cd, --대내시스템구분코드 ( SELECT cmmn_cd_nm FROM SCM.tc_sc_cd WHERE cls_cd = 'SCM_0000' AND cmmn_cd = A.INTN_SYS_DIV_CD ) AS intn_sys_div_nm, --대내시스템구분코드명 A.scrin_nm, --화면명 A.scrin_url, --화면URL A.scrin_dc, --화면설명 A.hpcm_file_nm, --도움말파일명 A.pge_no, --페이지번호 A.hpcm_vido_file_nm, --도움말영상파일명 A.use_yn, --사용여부 TO_CHAR(A.frst_regist_dt, 'YYYY-MM-DD HH:MM:DD') AS frst_regist_dt, A.frst_rgstr_id, ( SELECT DISTINCT korname FROM HRM.vm_hr01601 WHERE empno = A.frst_rgstr_id ) AS frst_rgstr_nm, TO_CHAR(A.last_updt_dt, 'YYYY-MM-DD HH:MM:DD') AS last_updt_dt, A.last_updusr_id, ( SELECT DISTINCT korname FROM HRM.vm_hr01601 WHERE empno = A.last_updusr_id ) AS last_updusr_nm, A.parm_vu FROM tm_ecs_intn_scrin A
, tm_ecs_intn_usr_athr B WHERE A.intn_sys_div_cd = SUBSTR(B.ATHR_ID, 0, 3) AND B.usr_id = #{usrId}
WHERE 1 = 1
AND A.scrin_id LIKE '%' || #{scrinId} || '%'
AND A.scrin_nm LIKE '%' || #{scrinNm} || '%'
AND A.intn_sys_div_cd = #{intnSysDivCd}
AND A.use_yn = #{useYn}
ORDER BY A.intn_sys_div_cd, A.scrin_id

mapper.delete:
/* TM_ECS_INTN_SCRIN_Dao_deleteScrinMng */
DELETE FROM
	tm_ecs_intn_scrin
WHERE
	scrin_id = #{scrinId}
